const aiAnswer = $('Execute node').first().json.answer;
const webhookData = $('Webhook').first().json;
const userQuery = webhookData.body?.question || "";
const dataset = $('Clean Data').first().json.dataset || [];
const columns = Object.keys(dataset[0] || {});
const qLower = userQuery.toLowerCase();

const dataForGemini = {};
for (const col of columns) {
  const values = dataset.map(r => r[col]).filter(v => v !== null && v !== undefined && v !== "");
  const isNumeric = values.every(v => typeof v === "number");
  if (isNumeric) {
    const sorted = [...values].sort((a, b) => a - b);
    const avg = Math.round(values.reduce((a, b) => a + b, 0) / values.length);
    dataForGemini[col] = { type: 'numeric', min: sorted[0], max: sorted[sorted.length-1], avg };
  } else {
    const counts = {};
    for (const v of values) counts[v] = (counts[v] || 0) + 1;
    const sorted = Object.entries(counts).sort((a,b) => b[1]-a[1]).slice(0, 10);
    dataForGemini[col] = { type: 'categorical', top10: sorted };
  }
}

const mentionedCols = columns.filter(col => qLower.includes(col.toLowerCase()));
let crossTabData = null;
let crossTabDescription = '';
if (mentionedCols.length >= 2) {
  const col1 = mentionedCols[0];
  const col2 = mentionedCols[1];
  const tab = {};
  for (const row of dataset) {
    const v1 = String(row[col1] || 'Unknown');
    const v2 = String(row[col2] || 'Unknown');
    if (!tab[v1]) tab[v1] = {};
    tab[v1][v2] = (tab[v1][v2] || 0) + 1;
  }
  crossTabData = Object.entries(tab)
    .sort((a, b) => Object.values(b[1]).reduce((x,y)=>x+y,0) - Object.values(a[1]).reduce((x,y)=>x+y,0))
    .slice(0, 10)
    .reduce((acc, [k, v]) => { acc[k] = v; return acc; }, {});
  crossTabDescription = `Cross-tabulation of "${col1}" vs "${col2}" (top 10 ${col1} values):`;
} else if (mentionedCols.length === 1) {
  crossTabDescription = `Single column data for "${mentionedCols[0]}":`;
  crossTabData = dataForGemini[mentionedCols[0]];
} else {
  crossTabDescription = 'Full dataset aggregated data:';
  crossTabData = dataForGemini;
}

const prompt = `You are a premium HTML dashboard generator for AxionDrive, a car analytics platform.
Question: ${userQuery}
Dataset has ${dataset.length} rows with these columns: ${columns.join(', ')}
${crossTabDescription}
${JSON.stringify(crossTabData, null, 2)}

IMPORTANT — READ QUESTION FIRST BEFORE GENERATING ANYTHING:
- If question asks for a SINGLE chart type (pie, bar, line, donut, pie chart, bar graph) → generate ONLY that one chart, full width, centered, no KPI strip, no map, no other charts, no insights bar
- If question asks for "dashboard", "full dashboard", "overview", "analytics", "kpi" → generate the complete layout
- NEVER show the full dashboard layout for a single chart request
- NEVER show KPI cards for a single chart request

STRICT RULES — DO NOT DEVIATE:

1. Return ONLY raw HTML starting with <!DOCTYPE html>. No markdown, no backticks, no explanation.

2. EXACT CSS VARIABLES:
--bg: #0a0a0f
--surface: #12121a
--surface2: #1a1a26
--border: rgba(255,255,255,0.06)
--accent: #e8ff47
--accent2: #47c8ff
