return [{ json: { prompt, aiAnswer, question: userQuery, dataset } }];

// Get all rows
let rawData = $input.all().map(item => item.json);

// Remove completely empty rows
rawData = rawData.filter(row =>
  Object.values(row).some(value => value !== null && value !== "")
);

// Clean + normalize values
rawData = rawData.map(row => {
  const cleaned = {};
  for (let key in row) {
    let value = row[key];
    if (typeof value === "string") {
      value = value.trim();
      if (value === "") value = null;
    }
    if (
      value !== null &&
      value !== "" &&
      !isNaN(value) &&
      value !== true &&
      value !== false
    ) {
      value = Number(value);
    }
    cleaned[key] = value;
  }
  return cleaned;
});

// Remove exact duplicates
const seen = new Set();
rawData = rawData.filter(row => {
  const str = JSON.stringify(row);
  if (seen.has(str)) return false;
  seen.add(str);
  return true;
});

// Detect column types
const columnTypes = {};
if (rawData.length > 0) {
  const sample = rawData[0];
  for (let key in sample) {
    const values = rawData.map(r => r[key]).filter(v => v !== null);
    const numericCount = values.filter(v => typeof v === "number").length;
    const totalCount = values.length;
    if (numericCount / totalCount > 0.7) {
      columnTypes[key] = "numeric";
    } else {
      columnTypes[key] = "categorical";
    }
  }
}

// Auto-detect critical columns (categorical with less than 5% nulls)
const criticalColumns = Object.keys(columnTypes).filter(col => {
  if (columnTypes[col] !== 'categorical') return false;
  const nullCount = rawData.filter(r => r[col] === null || r[col] === undefined).length;
  const nullPercent = nullCount / rawData.length;
  return nullPercent < 0.05;
});

// Delete rows where critical columns are null
rawData = rawData.filter(row => {
  return criticalColumns.every(col => {
    return row[col] !== null && row[col] !== undefined && row[col] !== '';
  });
});

return [
  {
    json: {
      dataset: rawData,
      eda: {
        total_rows: rawData.length,
        total_columns: Object.keys(columnTypes).length,
        column_types: columnTypes,
        critical_columns: criticalColumns
      }
    }
  }
];

const webhookData = $('Webhook').first().json;
const userQuery = webhookData.body?.question || "Analyse the dataset";
const dataset = $json.dataset || [];
const columns = Object.keys(dataset[0] || {});
const sample = dataset.slice(0, 3);

// Detect if question is general knowledge (not dataset specific)
const datasetKeywords = ['price', 'make', 'model', 'fuel', 'transmission', 'location', 'city', 'count', 'average', 'avg', 'top', 'list', 'how many', 'which city', 'most expensive', 'cheapest', 'dataset', 'cars in', 'total'];
const isDatasetQuestion = datasetKeywords.some(k => userQuery.toLowerCase().includes(k));

let prompt;

if (!isDatasetQuestion) {
  prompt = `You are AxionDrive, an AI-powered car analytics assistant built for the Indian car market.
You have access to a dataset of ${dataset.length} cars with columns: ${columns.join(', ')}.
Answer this question in plain conversational English. Be helpful and concise.
Question: ${userQuery}
STRICT RULES:
- Reply in 3-5 clean sentences maximum
- Always introduce yourself as AxionDrive when asked what you are
- If asked about specific car names or models, look them up from the dataset context, not generic knowledge
- NO JavaScript code, NO function, NO return statement
- NO backticks, NO markdown
- Just plain readable text answer
- If user asks about "this graph", "this chart", "explain this", "what is this based on" — reply with:
  "Please mention what you'd like to know specifically, for example: 'What is the bar graph of makes based on?' and I'll answer it directly."
- NEVER start mid-sentence — always start from the beginning`;
} else {
  // Dataset question — generate JavaScript code
  prompt = `You are a JavaScript code generator. Write a function body to answer this question.
Question: ${userQuery}
The variable 'dataset' is an array of ${dataset.length} objects.
Columns available: ${JSON.stringify(columns)}
Sample (first 3 rows): ${JSON.stringify(sample, null, 2)}

STRICT RULES:
- Write ONLY the function body
- No function declaration
- No markdown, no backticks, no explanation
- Last line MUST be: return { answer: "your answer here" }
- Always convert answer to readable string
- Use toLocaleString('en-IN') for prices

FORMATTING RULES — VERY IMPORTANT:
- NEVER return a single long comma-separated paragraph
- For lists of items (top 10 cars, top 5 makes etc): format each item on its own line using \\n
  Example: "1. Audi A6 - ₹15,00,000\\n2. Mercedes S-Class - ₹15,00,000\\n3. Skoda Superb - ₹15,00,000"
- For summary stats: use a clean structured format like:
  "Total Cars: 226\\nAverage Price: ₹12,42,101\\nMost Expensive: Audi A6 - ₹15,00,000\\nCheapest: Tata Hexa - ₹8,00,000"
- For single value answers: just return the value cleanly
- Always use ₹ symbol for Indian prices instead of plain numbers
- NEVER dump all data in one line separated by commas

- For KPI questions: calculate total count, avg price, most expensive, cheapest, most common make
- NEVER return null, array or object directly`;
}

return [{ json: { question: userQuery, prompt, dataset } }];

