var code = $json.code || "";
var question = $('Webhook').first().json.body.question.toLowerCase();
var keywords = ['dashboard','kpi','graph','pie chart','line chart','bar graph','chart'];
var isVisual = false;
for (var i = 0; i < keywords.length; i++) {
  if (question.indexOf(keywords[i]) !== -1) { isVisual = true; break; }
}
if (isVisual) {
  return [{ json: { answer: "VISUAL_REQUEST" } }];
}
var cleanCode = code.replace(/```javascript/gi, '').replace(/```js/gi, '').replace(/```/g, '').trim();
var codeStart = cleanCode.search(/(const|let|var|function|\/\/)/);

// If no JS code found, it's a plain text answer — return directly
if (codeStart === -1) {
  return [{ json: { answer: cleanCode } }];
}

if (codeStart > 0) { cleanCode = cleanCode.substring(codeStart); }
try {
  var dataset = $('Clean Data').first().json.dataset || [];
  var fn = new Function('dataset', cleanCode);
  var result = fn(dataset);
  var answer = typeof result === 'object' ? (result.answer || JSON.stringify(result)) : String(result);
  return [{ json: { answer: answer } }];
} catch (err) {
  // Return raw text instead of error message
  return [{ json: { answer: code.replace(/```javascript/gi, '').replace(/```js/gi, '').replace(/```/g, '').trim() } }];
}

const dataset = $('Clean Data').first().json.dataset;
const htmlBinary = $('Prepare Email Attachment(0,1)').first().binary;
const question = $('Webhook').first().json.body.question || "";

const headers = Object.keys(dataset[0]);
const csvRows = [headers.join(',')];

for (const row of dataset) {
  const values = headers.map(h => {
    let val = row[h];

    if (val === null || val === undefined || val === '') return 'N/A';

    val = String(val).trim();

    if (val === '') return 'N/A';

    if (val.includes(',') || val.includes('"') || val.includes('\n')) {
      val = '"' + val.replace(/"/g, '""') + '"';
    }

    return val;
  });
  csvRows.push(values.join(','));
}

const csvString = csvRows.join('\n');
const binary = Buffer.from(csvString, 'utf8').toString('base64');
const filename = `car_data_cleaned_${Date.now()}.csv`;

return [{
  json: { filename, question, csvString },
  binary: {
    ...htmlBinary,
    cleanedCsv: {
      data: binary,
      mimeType: 'text/csv',
      fileName: filename
    }
  }
}];

let rawHtml = "";
try {
  const groqOutput = $('Groq - Genrate HTML').first().json;

  if (groqOutput.choices?.[0]?.message?.content) {
    rawHtml = groqOutput.choices[0].message.content;
  } else if (groqOutput.content?.parts?.[0]?.text) {
    rawHtml = groqOutput.content.parts[0].text;
  } else if (groqOutput.text) {
    rawHtml = groqOutput.text;
  } else if (groqOutput.content && typeof groqOutput.content === 'string') {
    rawHtml = groqOutput.content;
  } else if (groqOutput.candidates?.[0]?.content?.parts?.[0]?.text) {
    rawHtml = groqOutput.candidates[0].content.parts[0].text;
  } else {
    rawHtml = `<html><body><h1>Debug</h1><pre>${JSON.stringify(groqOutput, null, 2)}</pre></body></html>`;
  }
} catch(e) {
  rawHtml = `<html><body><h1>Error</h1><p>${e.message}</p></body></html>`;
}

const html = rawHtml
  .replace(/```html/gi, '')
  .replace(/```/g, '')
  .trim();

const question = $('Webhook').first().json.body.question || "";
const filename = `dashboard_${Date.now()}.html`;
const binary = Buffer.from(html, 'utf8').toString('base64');

return [{
  json: { filename, html, answer: html, question: question },
  binary: {
    htmlFile: {
      data: binary,
      mimeType: 'text/html',
      fileName: filename
    }
  }
}];
